"use strict";(self.webpackChunkmy_personal_website=self.webpackChunkmy_personal_website||[]).push([[2392],{3436:(e,t,a)=>{a.d(t,{A:()=>o});const o=a.p+"assets/images/pvnm-590e436f4f69666877aafdec5c44cf51.png"},8453:(e,t,a)=>{a.d(t,{R:()=>i,x:()=>r});var o=a(6540);const s={},n=o.createContext(s);function i(e){const t=o.useContext(n);return o.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:i(e.components),o.createElement(n.Provider,{value:t},e.children)}},8767:e=>{e.exports=JSON.parse('{"permalink":"/blog/websites","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2026-03-31-Websites/index.md","source":"@site/blog/2026-03-31-Websites/index.md","title":"Websites","description":"After graduating college with a Computer Science degree in 2020, I spent a lot of time looking for jobs. After a full year of no job prospects, I was getting frustrated, and was willing to take any job that I could get in the tech field. My old roommate from college would talk to me about ideas to get a business started ourselves. We would play Apex Legends together almost everyday (That game is fun as heck!), and sometimes we\'d talk about this topic in between matches. Our first go at something was to create a motion detection program using the programming language Python. It has a image reading library called Open-CV. We each bought a cheap camera lens and Raspberry Pie to create the camera and test it out. Not only was it capable of detecting motion, but it would also save the specific recording in which motion was detected, and delete the rest in order to save on storage. We were planning on selling this motion detecting camera to businesses. However, this all fell through for reasons I honestly can\'t remember. I believe it was because of the constant issues we had with the program, and we got frustrated trying to find fixes to errors. We just silently moved on to the next idea, which was website development.","date":"2026-03-31T00:00:00.000Z","tags":[{"inline":true,"label":"Goals","permalink":"/blog/tags/goals"}],"readingTime":4,"hasTruncateMarker":false,"authors":[{"name":"Travis Blanks","title":"Jack of All Trades","url":"https://travisblanks.com","imageURL":"/img/channels4_profile.jpg","key":"Gekaku","page":null}],"frontMatter":{"slug":"websites","title":"Websites","authors":"Gekaku","tags":["Goals"]},"unlisted":false,"nextItem":{"title":"Pokemon Showdown","permalink":"/blog/pokemon-showdown"}}')},9459:(e,t,a)=>{a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>c,frontMatter:()=>i,metadata:()=>o,toc:()=>d});var o=a(8767),s=a(4848),n=a(8453);const i={slug:"websites",title:"Websites",authors:"Gekaku",tags:["Goals"]},r=void 0,l={authorsImageUrls:[void 0]},d=[];function h(e){const t={a:"a",img:"img",p:"p",...(0,n.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.p,{children:"After graduating college with a Computer Science degree in 2020, I spent a lot of time looking for jobs. After a full year of no job prospects, I was getting frustrated, and was willing to take any job that I could get in the tech field. My old roommate from college would talk to me about ideas to get a business started ourselves. We would play Apex Legends together almost everyday (That game is fun as heck!), and sometimes we'd talk about this topic in between matches. Our first go at something was to create a motion detection program using the programming language Python. It has a image reading library called Open-CV. We each bought a cheap camera lens and Raspberry Pie to create the camera and test it out. Not only was it capable of detecting motion, but it would also save the specific recording in which motion was detected, and delete the rest in order to save on storage. We were planning on selling this motion detecting camera to businesses. However, this all fell through for reasons I honestly can't remember. I believe it was because of the constant issues we had with the program, and we got frustrated trying to find fixes to errors. We just silently moved on to the next idea, which was website development."}),"\n",(0,s.jsx)(t.p,{children:"We had the idea to create a web dev company. We called it Chyme. I'm not sure how we came up with the name, but I'm pretty sure it was my old roommate's idea. It was always his idea. He was always the brains of the operation leading me along. I was never the smartest programmer. Heck, I'm using AI as a crutch for all of the project I'm working on. The word crutch is saying it lightly. It's more like a wheelchair for me at this point. I was pretty confident in this endeavor. My dad used to create websites about 15-20 years ago, so I know I could always ask him for help if I needed it. He even gave me a list of things to ask our potential clients about what type of website they want. I felt like everything would work out this time. Unfortunately, we couldn't find any clients. We would reach out to small businesses, and post ads on Facebook, but it led nowhere. It pushed me further down into the depths of hopelessness. I felt like there just wasn't any opportunities out there."}),"\n",(0,s.jsx)(t.p,{children:"During my time in Albuquerque, I decided to give web design another try. I took my dad's old web design business, and made it my own. I once again tried reaching out to small businesses in Albuquerque, even going in personally and handing out business cards. Thankfully, I got one business owner to believe in me. It was a business that specializes in car audio. The business was right across the street from the U-Haul I was working at. I looked across the street one day during my shift, and decided to give it one last try. After my shift was over, I walk into the store with my U-Haul shirt still on. I usually wear something business casual, but I didn't care how I looked anymore. I was just so sick of preparing; all I need to do is go in there and tell them what I can do for their business. I was shocked to see that they agreed to my offer. I immediately went home and began working on website mock-ups. In the end, I made about $800 working on their website."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.a,{href:"https://paradisevillagenm.com/",children:(0,s.jsx)(t.img,{alt:"A website I created a few years ago for a company called Paradise Village",src:a(3436).A+"",width:"1892",height:"871"})})}),"\n",(0,s.jsx)(t.p,{children:"Today, that website is still up and running, but it's a mess. It hasn't been updated since 2023. Now that I'm unemployed and back living with my parents, I've decided to give it one more try. The third time's the charm. I plan on revamping that website I worked on in the past, as well as work on my own personal projects. You're looking at one of my projects right now. I'll talk about the other websites I'm making in the future once I've at least gotten the first page up."}),"\n",(0,s.jsx)(t.p,{children:"Making websites is a great way for me to express myself. I can design them any way I want (my personal ones at least), and I can put whatever I want on them. It really is refreshing to create something that isn't bound by rules. When I say 'bound by rules', I'm referring to social media, which is full of restrictions on what you can post and how you can post it. This is a good opportunity for me to show people there is more to the internet than 5 websites."})]})}function c(e={}){const{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(h,{...e})}):h(e)}}}]);